import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RecibeocService } from '../../services/recibeoc.service';
import { RecibeOC } from '../../models/interfaces';

@Component({
  selector: 'app-recibeoc',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './recibeoc.component.html',
  styleUrls: ['./recibeoc.component.scss']
})
export class RecibeocComponent implements OnInit {
  registros: RecibeOC[] = [];
  registroEditando: RecibeOC | null = null;
  busquedaFolio: number | null = null;
  mensaje = '';
  tipoMensaje: 'success' | 'error' | '' = '';
  cargando = false;

  constructor(private svc: RecibeocService) {}

  ngOnInit(): void {
    this.cargar();
  }

  cargar(): void {
    this.cargando = true;
    this.svc.getAll().subscribe({
      next: res => {
        this.registros = res.data ?? [];
        this.cargando = false;
      },
      error: () => {
        this.mostrarMensaje('Error al cargar registros', 'error');
        this.cargando = false;
      }
    });
  }

  buscarPorFolio(): void {
    if (!this.busquedaFolio) { this.cargar(); return; }
    this.cargando = true;
    this.svc.getByFolio(this.busquedaFolio).subscribe({
      next: res => { this.registros = res.data ?? []; this.cargando = false; },
      error: () => { this.mostrarMensaje('Error en búsqueda', 'error'); this.cargando = false; }
    });
  }

  editar(r: RecibeOC): void {
    this.registroEditando = { ...r };
  }

  cancelarEdicion(): void {
    this.registroEditando = null;
  }

  guardar(): void {
    if (!this.registroEditando) return;
    this.svc.update(this.registroEditando.id, this.registroEditando).subscribe({
      next: () => {
        this.mostrarMensaje('Registro actualizado correctamente', 'success');
        this.registroEditando = null;
        this.cargar();
      },
      error: () => this.mostrarMensaje('Error al actualizar', 'error')
    });
  }

  eliminar(id: number): void {
    if (!confirm('¿Seguro que deseas eliminar este registro? Se guardará un respaldo automáticamente.')) return;
    this.svc.delete(id).subscribe({
      next: () => {
        this.mostrarMensaje('Registro eliminado y respaldado', 'success');
        this.cargar();
      },
      error: () => this.mostrarMensaje('Error al eliminar', 'error')
    });
  }

  private mostrarMensaje(msg: string, tipo: 'success' | 'error'): void {
    this.mensaje = msg;
    this.tipoMensaje = tipo;
    setTimeout(() => { this.mensaje = ''; this.tipoMensaje = ''; }, 3500);
  }
}
<div class="page-header">
  <h1>Recepción de Órdenes de Compra</h1>

  <!-- Búsqueda por folio -->
  <div class="search-bar">
    <input
      type="number"
      [(ngModel)]="busquedaFolio"
      placeholder="Buscar por folio..."
      (keyup.enter)="buscarPorFolio()"
    />
    <button class="btn btn-primary" (click)="buscarPorFolio()">Buscar</button>
    <button class="btn btn-secondary" (click)="busquedaFolio = null; cargar()">Ver todos</button>
  </div>
</div>

<!-- Mensajes de alerta -->
<div *ngIf="mensaje" class="alerta" [ngClass]="'alerta-' + tipoMensaje">
  {{ mensaje }}
</div>

<!-- Spinner de carga -->
<div *ngIf="cargando" class="spinner-wrap">
  <span class="spinner"></span> Cargando...
</div>

<!-- Tabla de registros -->
<div class="tabla-wrap" *ngIf="!cargando">
  <table>
    <thead>
      <tr>
        <th>ID</th>
        <th>Folio</th>
        <th>Renglón</th>
        <th>Material</th>
        <th>Proveedor</th>
        <th>Cantidad</th>
        <th>Fecha Recibida</th>
        <th>Factura</th>
        <th>Estatus</th>
        <th>Acciones</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let r of registros">
        <td>{{ r.id }}</td>
        <td>{{ r.folio }}</td>
        <td>{{ r.renglon }}</td>
        <td>{{ r.material }}</td>
        <td>{{ r.provedor }}</td>
        <td>{{ r.cantidad }}</td>
        <td>{{ r.frecibida | date:'dd/MM/yyyy' }}</td>
        <td>{{ r.factura }}</td>
        <td>
          <span class="badge" [ngClass]="r.estatus === 1 ? 'badge-ok' : 'badge-pend'">
            {{ r.estatus === 1 ? 'Activo' : 'Inactivo' }}
          </span>
        </td>
        <td class="acciones">
          <button class="btn btn-sm btn-edit" (click)="editar(r)">✏️ Editar</button>
          <button class="btn btn-sm btn-delete" (click)="eliminar(r.id)">🗑️ Eliminar</button>
        </td>
      </tr>
      <tr *ngIf="registros.length === 0">
        <td colspan="10" class="sin-datos">No hay registros</td>
      </tr>
    </tbody>
  </table>
</div>

<!-- Modal de edición -->
<div class="modal-overlay" *ngIf="registroEditando" (click)="cancelarEdicion()">
  <div class="modal" (click)="$event.stopPropagation()">
    <h2>Editar Recepción #{{ registroEditando.id }}</h2>

    <div class="form-grid">
      <label>Folio
        <input type="number" [(ngModel)]="registroEditando.folio" />
      </label>
      <label>Renglón
        <input type="number" [(ngModel)]="registroEditando.renglon" />
      </label>
      <label>Cantidad
        <input type="number" step="0.01" [(ngModel)]="registroEditando.cantidad" />
      </label>
      <label>Precio
        <input type="number" step="0.00001" [(ngModel)]="registroEditando.precio" />
      </label>
      <label>Fecha Recibida
        <input type="date" [(ngModel)]="registroEditando.frecibida" />
      </label>
      <label>Hora Recibida
        <input type="time" [(ngModel)]="registroEditando.hrecibida" />
      </label>
      <label>Factura
        <input type="text" maxlength="11" [(ngModel)]="registroEditando.factura" />
      </label>
      <label>Fecha Factura
        <input type="date" [(ngModel)]="registroEditando.fechafac" />
      </label>
      <label>No. Semana
        <input type="number" [(ngModel)]="registroEditando.nosemana" />
      </label>
      <label>U. Medida
        <input type="text" maxlength="10" [(ngModel)]="registroEditando.umedida" />
      </label>
      <label>Material
        <input type="text" maxlength="80" [(ngModel)]="registroEditando.material" />
      </label>
      <label>Proveedor
        <input type="text" maxlength="50" [(ngModel)]="registroEditando.provedor" />
      </label>
      <label>Usuario
        <input type="text" [(ngModel)]="registroEditando.usuario" />
      </label>
      <label>Estatus
        <select [(ngModel)]="registroEditando.estatus">
          <option [value]="1">Activo</option>
          <option [value]="0">Inactivo</option>
        </select>
      </label>
      <label class="full-width">Observación
        <textarea maxlength="100" [(ngModel)]="registroEditando.observacion"></textarea>
      </label>
    </div>

    <div class="modal-footer">
      <button class="btn btn-secondary" (click)="cancelarEdicion()">Cancelar</button>
      <button class="btn btn-primary" (click)="guardar()">Guardar cambios</button>
    </div>
  </div>
</div>
